```typescript
type ExperimentId = string;
type VariantId = string;

type ExperimentStatus = "DRAFT" | "RUNNING" | "PAUSED" | "STOPPED" | "CONCLUDED" | "ARCHIVED";

type AllocationStrategy = "RANDOM" | "DETERMINISTIC_HASH" | "STICKY_SESSION";

type Variant = {
  variantId: VariantId;
  name: string;                    // e.g. "control", "treatment_a"
  description?: string;
  allocationPercent: number;       // Must sum to 100 across all variants
  isControl: boolean;
};

type TargetMetric = {
  name: string;                    // e.g. "checkout_conversion", "revenue_per_user"
  type: "BINARY" | "CONTINUOUS";  // BINARY = converted/not; CONTINUOUS = revenue amount
  isPrimary: boolean;              // Only one primary metric per experiment
};

type CreateExperimentInput = {
  name: string;
  hypothesis: string;
  variants: Variant[];
  targetMetrics: TargetMetric[];
  allocationStrategy: AllocationStrategy;
  trafficPercent: number;          // Percent of eligible subjects enrolled (0–100)
  eligibilityCriteria?: Record<string, unknown>; // e.g. { country: "US", plan: "pro" }
  startDate?: Timestamp;
  endDate?: Timestamp;
};

type Experiment = CreateExperimentInput & {
  experimentId: ExperimentId;
  status: ExperimentStatus;
  winningVariantId?: VariantId;
  conclusionNotes?: string;
  createdAt: Timestamp;
  startedAt?: Timestamp;
  stoppedAt?: Timestamp;
  concludedAt?: Timestamp;
};

type VariantAssignment = {
  experimentId: ExperimentId;
  subjectId: string;
  variantId: VariantId;
  variantName: string;
  assignedAt: Timestamp;
  exposed: boolean;
};

type AssignVariantInput = {
  experimentId: ExperimentId;
  subjectId: string;
  subjectAttributes?: Record<string, unknown>;
};

type RecordExposureInput = {
  experimentId: ExperimentId;
  subjectId: string;
  exposedAt?: Timestamp;
};

type RecordMetricInput = {
  experimentId: ExperimentId;
  subjectId: string;
  metricName: string;
  value: number;                   // 1/0 for BINARY; numeric for CONTINUOUS
  recordedAt?: Timestamp;
};

type VariantResult = {
  variantId: VariantId;
  variantName: string;
  subjectsAssigned: number;
  subjectsExposed: number;
  conversions: number;
  conversionRate: number;
  meanValue?: number;
  confidenceIntervalLow: number;
  confidenceIntervalHigh: number;
  relativeUplift?: number;         // Relative to control variant
  pValue?: number;
  isStatisticallySignificant: boolean;
};

type ExperimentResults = {
  experimentId: ExperimentId;
  primaryMetric: string;
  minimumDetectableEffect: number;
  requiredSampleSize: number;
  currentSampleSize: number;
  computedAt: Timestamp;
  variants: VariantResult[];
  hasSignificantWinner: boolean;
  recommendedWinnerVariantId?: VariantId;
};

type ConcludeExperimentInput = {
  experimentId: ExperimentId;
  winningVariantId: VariantId;
  conclusionNotes?: string;
};

type ListExperimentsInput = {
  status?: ExperimentStatus;
  primaryMetric?: string;
  pagination: PaginationInput;
};
```

```typescript
type FeedEntryId = string;
type ActivityTypeId = string;

type AudienceStrategy =
  | "ACTOR_ONLY"          // Only visible to the actor (personal activity log)
  | "FOLLOWERS"           // Visible to users following the actor
  | "WORKSPACE"           // Visible to all members of the actor's workspace
  | "ENTITY_WATCHERS"     // Visible to users watching the related entity
  | "PUBLIC";             // Visible to anyone

type EntityRef = {
  entityType: string;
  entityId: string;
};

type RegisterActivityTypeInput = {
  eventName: string;               // e.g. "order.status_changed", "comment.created"
  sourceModule: string;            // e.g. "orders", "comments"
  displayTemplate: string;         // e.g. "{{actor.name}} updated order #{{entity.id}} to {{data.newStatus}}"
  audienceStrategy: AudienceStrategy;
  icon?: string;
  groupable: boolean;              // If true, consecutive similar entries can be grouped
};

type ActivityType = RegisterActivityTypeInput & {
  activityTypeId: ActivityTypeId;
  createdAt: Timestamp;
};

type IngestEventInput = {
  eventName: string;
  actorId?: UserId;
  actorType?: string;              // e.g. "user", "system", "api_key"
  entityRef?: EntityRef;
  workspaceId?: string;
  data: Record<string, unknown>;  // Event payload; used for template rendering
  occurredAt: Timestamp;
  idempotencyKey: string;         // Source event ID; prevents duplicate entries
};

type FeedEntry = {
  entryId: FeedEntryId;
  activityTypeId: ActivityTypeId;
  eventName: string;
  actorId?: UserId;
  actorType?: string;
  actorDisplayName?: string;
  entityRef?: EntityRef;
  workspaceId?: string;
  renderedText: string;            // Pre-rendered from displayTemplate and data
  data: Record<string, unknown>;
  visible: boolean;
  occurredAt: Timestamp;
  ingestedAt: Timestamp;
  groupKey?: string;               // Non-null for groupable activities; used to collapse related entries
};

type GetFeedInput = {
  audience: "PERSONAL" | "WORKSPACE" | "PUBLIC_PROFILE";
  actorId?: UserId;                // For PERSONAL and PUBLIC_PROFILE audiences
  workspaceId?: string;            // For WORKSPACE audience
  eventNames?: string[];           // Filter to specific activity types
  entityRef?: EntityRef;
  fromDate?: Timestamp;
  toDate?: Timestamp;
  pagination: FeedPaginationInput;
};

type FeedPaginationInput = {
  cursor?: string;                 // Cursor-based pagination for real-time feeds
  limit: number;
};
