  uploadUrl?: string;              // Presigned URL; only present in UPLOADING state
  fileName?: string;
  fileSizeBytes?: number;
  totalRows?: number;
  parsedRows?: number;
  validRows?: number;
  errorRows?: number;
  committedRows?: number;
  failedRows?: number;
